# SECURE: resolve path and validate it stays within base directory
import os
from flask import send_file, request, abort

UPLOAD_DIR = os.path.realpath('/var/app/uploads')

@app.route('/download')
def download():
    filename = request.args.get('file', '')

    # Reject filenames with suspicious patterns early
    if '..' in filename or filename.startswith('/'):
        abort(400)

    # Resolve the absolute path — this collapses all ../ sequences
    filepath = os.path.realpath(os.path.join(UPLOAD_DIR, filename))

    # Enforce that the resolved path is inside the upload directory
    if not filepath.startswith(UPLOAD_DIR + os.sep):
        abort(403)

    return send_file(filepath)

