ALLOWED_EXTENSIONS = {'.pdf', '.docx', '.xlsx'}

def is_safe_filename(filename):
    ext = os.path.splitext(filename)[1].lower()
    # Check extension and that no path separators are present
    return ext in ALLOWED_EXTENSIONS and os.sep not in filename
